index c1ce364eb179..5180a82ec2db 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1515,6 +1515,94 @@ static Instruction *foldBoxMultiply(BinaryOperator &I) {

   return nullptr;
 }
+/// Fold ceiling division pattern:
+/// (X >> C) + zext(icmp ne (and X, (2^C - 1)), 0) --> (X + (2^C - 1)) >> C
+/// This implements ceil(X / 2^C) using the standard formula.
+static Instruction *foldCeilDivWithPow2(BinaryOperator &I,
+                                        InstCombiner::BuilderTy &Builder,
+                                        const SimplifyQuery &Q) {
+  Value *LHS = I.getOperand(0);
+  Value *RHS = I.getOperand(1);
+  Type *Ty = I.getType();
+
+  // Match pattern: (lshr X, C) + zext(icmp ne (and X, mask), 0)
+  // where mask = 2^C - 1
+  Value *X, *Y;
+  const APInt *ShiftAmt, *MaskC;
+  
+  // Try both operand orders
+  // Pattern: (lshr X, C) + zext(icmp ne (and X, mask), 0)
+  if (match(LHS, m_LShr(m_Value(X), m_APInt(ShiftAmt))) &&
+      match(RHS, m_OneUse(m_ZExt(m_OneUse(
+          m_SpecificICmp(ICmpInst::ICMP_NE,
+              m_OneUse(m_And(m_Value(Y), m_APInt(MaskC))),
+              m_ZeroInt()))))) &&
+      X == Y) {
+    // Verify mask = 2^C - 1 (all lower C bits set)
+    unsigned C = ShiftAmt->getZExtValue();
+    unsigned BitWidth = Ty->getScalarSizeInBits();
+    if (C == 0 || C >= BitWidth)
+      return nullptr;
+    
+    APInt ExpectedMask = APInt::getLowBitsSet(BitWidth, C);
+    if (*MaskC != ExpectedMask)
+      return nullptr;
+    
+    // Verify the shift has single use
+    if (!LHS->hasOneUse())
+      return nullptr;
+    
+    // Check that X + mask won't overflow by examining known bits
+    KnownBits XKnown = computeKnownBits(X, Q);
+    APInt MaxX = XKnown.getMaxValue();
+    if (MaxX.ugt(APInt::getMaxValue(BitWidth) - *MaskC))
+      return nullptr;
+    
+    // Create (X + mask) >> C
+    Value *Add = Builder.CreateAdd(X, ConstantInt::get(Ty, *MaskC), "",
+                                    I.hasNoUnsignedWrap(), I.hasNoSignedWrap());
+    auto *LShr = BinaryOperator::CreateLShr(Add, ConstantInt::get(Ty, C));
+    LShr->copyIRFlags(&I);
+    return LShr;
+  }
+  
+  // Try swapped order: zext(icmp ne (and X, mask), 0) + (lshr X, C)
+  if (match(RHS, m_LShr(m_Value(X), m_APInt(ShiftAmt))) &&
+      match(LHS, m_OneUse(m_ZExt(m_OneUse(
+          m_SpecificICmp(ICmpInst::ICMP_NE,
+              m_OneUse(m_And(m_Value(Y), m_APInt(MaskC))),
+              m_ZeroInt()))))) &&
+      X == Y) {
+    // Verify mask = 2^C - 1 (all lower C bits set)
+    unsigned C = ShiftAmt->getZExtValue();
+    unsigned BitWidth = Ty->getScalarSizeInBits();
+    if (C == 0 || C >= BitWidth)
+      return nullptr;
+    
+    APInt ExpectedMask = APInt::getLowBitsSet(BitWidth, C);
+    if (*MaskC != ExpectedMask)
+      return nullptr;
+    
+    // Verify the shift has single use
+    if (!RHS->hasOneUse())
+      return nullptr;
+    
+    // Check that X + mask won't overflow by examining known bits
+    KnownBits XKnown = computeKnownBits(X, Q);
+    APInt MaxX = XKnown.getMaxValue();
+    if (MaxX.ugt(APInt::getMaxValue(BitWidth) - *MaskC))
+      return nullptr;
+    
+    // Create (X + mask) >> C
+    Value *Add = Builder.CreateAdd(X, ConstantInt::get(Ty, *MaskC), "",
+                                    I.hasNoUnsignedWrap(), I.hasNoSignedWrap());
+    auto *LShr = BinaryOperator::CreateLShr(Add, ConstantInt::get(Ty, C));
+    LShr->copyIRFlags(&I);
+    return LShr;
+  }
+  
+  return nullptr;
+}

 Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   if (Value *V = simplifyAddInst(I.getOperand(0), I.getOperand(1),
@@ -1553,6 +1641,9 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   if (Instruction *R = combineAddSubWithShlAddSub(Builder, I))
     return R;

+  if (Instruction *R = foldCeilDivWithPow2(I, Builder, SQ.getWithInstruction(\&I)))
+    return R;
+
   Value *LHS = I.getOperand(0), *RHS = I.getOperand(1);
   if (Instruction *R = foldAddLikeCommutative(LHS, RHS, I.hasNoSignedWrap(),
                                               I.hasNoUnsignedWrap()))

